1	type Item = {
2	  type: string;
3	  material?: string;
4	  cursed?: boolean;
5	  enchantment?: number;
6	};
7	
8	type Customer = { yearsWithMHPCO: number };
9	
10	type QuoteStep = { op: "quote"; items: Item[] };
11	
12	type Damage = { itemType: string; amount: number };
13	
14	type ClaimStep = {
15	  op: "claim";
16	  policy: number;
17	  incident: { cause: string; damages: Damage[] };
18	};
19	
20	type Step = QuoteStep | ClaimStep;
21	
22	type Scenario = {
23	  customer: Customer;
24	  steps: Step[];
25	};
26	
27	type ScenarioResult = {
28	  results: { premium?: number; payout?: number; remainingCap?: number }[];
29	};
30	
31	const PROCESSING_FEE = 5;
32	
33	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
34	
35	const firstInsuranceSurcharge = (premium: number): number =>
36	  premium * FIRST_INSURANCE_SURCHARGE_RATE;
37	
38	const COMPONENT_PREMIUM = 25;
39	
40	const BASE_PREMIUMS: Record<string, number> = {
41	  sword: 100,
42	  amulet: 60,
43	  staff: 80,
44	  potion: 40,
45	  rune: COMPONENT_PREMIUM,
46	  moonstone: COMPONENT_PREMIUM,
47	};
48	
49	const BLOCK_PREMIUM = 60;
50	
51	const isBlock = (count: number): boolean => count === 3;
52	
53	const countBy = <T>(
54	  values: T[],
55	  keyOf: (value: T) => string,
56	): Record<string, number> =>
57	  values.reduce<Record<string, number>>((counts, value) => {
58	    counts[keyOf(value)] = (counts[keyOf(value)] ?? 0) + 1;
59	    return counts;
60	  }, {});
61	
62	const countByType = (items: Item[]): Record<string, number> =>
63	  countBy(items, (item) => item.type);
64	
65	const premiumForGroup = (type: string, count: number): number =>
66	  isBlock(count) ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];
67	
68	const basePremiumFor = (items: Item[]): number =>
69	  Object.entries(countByType(items)).reduce(
70	    (total, [type, count]) => total + premiumForGroup(type, count),
71	    0,
72	  );
73	
74	const roundUpToWholeGold = (amount: number): number => Math.ceil(amount);
75	
76	const roundDownToWholeGold = (amount: number): number => Math.floor(amount);
77	
78	const sumBy = (items: Item[], valueOf: (item: Item) => number): number =>
79	  items.reduce((total, item) => total + valueOf(item), 0);
80	
81	const surchargeFor = (
82	  items: Item[],
83	  qualifies: (item: Item) => boolean,
84	  rate: number,
85	): number =>
86	  sumBy(items, (item) =>
87	    qualifies(item) ? BASE_PREMIUMS[item.type] * rate : 0,
88	  );
89	
90	const CURSE_SURCHARGE_RATE = 0.5;
91	
92	const isCursed = (item: Item): boolean => item.cursed === true;
93	
94	const curseSurchargeFor = (items: Item[]): number =>
95	  surchargeFor(items, isCursed, CURSE_SURCHARGE_RATE);
96	
97	const ENCHANTMENT_SURCHARGE_RATE = 0.3;
98	
99	const ENCHANTMENT_SURCHARGE_THRESHOLD = 5;
100	
101	const isHighlyEnchanted = (item: Item): boolean =>
102	  (item.enchantment ?? 0) >= ENCHANTMENT_SURCHARGE_THRESHOLD;
103	
104	const enchantmentSurchargeFor = (items: Item[]): number =>
105	  surchargeFor(items, isHighlyEnchanted, ENCHANTMENT_SURCHARGE_RATE);
106	
107	const discountFor = (
108	  qualifies: boolean,
109	  premium: number,
110	  rate: number,
111	): number => (qualifies ? premium * rate : 0);
112	
113	const LOYALTY_DISCOUNT_RATE = 0.2;
114	
115	const LOYALTY_YEARS_THRESHOLD = 2;
116	
117	const loyaltyDiscountFor = (customer: Customer, premium: number): number =>
118	  discountFor(
119	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD,
120	    premium,
121	    LOYALTY_DISCOUNT_RATE,
122	  );
123	
124	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
125	
126	const followUpDiscountFor = (isFollowUp: boolean, premium: number): number =>
127	  discountFor(isFollowUp, premium, FOLLOW_UP_DISCOUNT_RATE);
128	
129	const assertEach = <T>(
130	  values: T[],
131	  isValid: (value: T) => boolean,
132	  errorFor: (value: T) => string,
133	): void => {
134	  for (const value of values) {
135	    if (!isValid(value)) {
136	      throw new Error(errorFor(value));
137	    }
138	  }
139	};
140	
141	const isKnownItemType = (item: Item): boolean => item.type in BASE_PREMIUMS;
142	
143	const assertKnownItemTypes = (items: Item[]): void =>
144	  assertEach(items, isKnownItemType, (item) => `Unknown item type: ${item.type}`);
145	
146	const quotePremium = (
147	  customer: Customer,
148	  items: Item[],
149	  isFollowUp: boolean,
150	): number => {
151	  assertKnownItemTypes(items);
152	  const basePremium = basePremiumFor(items);
153	  return roundUpToWholeGold(
154	    basePremium +
155	      curseSurchargeFor(items) +
156	      enchantmentSurchargeFor(items) +
157	      firstInsuranceSurcharge(basePremium) -
158	      loyaltyDiscountFor(customer, basePremium) -
159	      followUpDiscountFor(isFollowUp, basePremium) +
160	      PROCESSING_FEE,
161	  );
162	};
163	
164	const DEDUCTIBLE = 100;
165	
166	const HIGH_ENCHANTMENT_THRESHOLD = 8;
167	
168	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
169	
170	const reimbursementRateFor = (item: Item | undefined): number =>
171	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
172	    ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
173	    : 1;
174	
175	const insuredItemFor = (
176	  insuredItems: Item[],
177	  damage: Damage,
178	): Item | undefined =>
179	  insuredItems.find((item) => item.type === damage.itemType);
180	
181	const payoutForDamage = (insuredItems: Item[], damage: Damage): number =>
182	  damage.amount * reimbursementRateFor(insuredItemFor(insuredItems, damage)) -
183	  DEDUCTIBLE;
184	
185	const insuredItemsForPolicy = (steps: Step[], policy: number): Item[] => {
186	  const policyStep = steps[policy];
187	  return policyStep.op === "quote" ? policyStep.items : [];
188	};
189	
190	const assertDamagesCoveredByPolicy = (
191	  insuredItems: Item[],
192	  damages: Damage[],
193	): void => {
194	  const insuredCounts = countByType(insuredItems);
195	  const damageCounts = countBy(damages, (damage) => damage.itemType);
196	  for (const [itemType, damageCount] of Object.entries(damageCounts)) {
197	    if (damageCount > (insuredCounts[itemType] ?? 0)) {
198	      throw new Error(`Item type not in policy: ${itemType}`);
199	    }
200	  }
201	};
202	
203	const isNonNegativeDamage = (damage: Damage): boolean => damage.amount >= 0;
204	
205	const assertNonNegativeDamageAmounts = (damages: Damage[]): void =>
206	  assertEach(
207	    damages,
208	    isNonNegativeDamage,
209	    (damage) => `Negative damage amount: ${damage.amount}`,
210	  );
211	
212	const claimPayout = (insuredItems: Item[], damages: Damage[]): number =>
213	  damages.reduce(
214	    (total, damage) => total + payoutForDamage(insuredItems, damage),
215	    0,
216	  );
217	
218	const INSURANCE_VALUES: Record<string, number> = {
219	  sword: 1000,
220	  amulet: 600,
221	  rune: 250,
222	};
223	
224	const CAP_MULTIPLIER = 2;
225	
226	const insuranceSumFor = (items: Item[]): number =>
227	  sumBy(items, (item) => INSURANCE_VALUES[item.type]);
228	
229	const remainingCapFor = (insuredItems: Item[], totalPaid: number): number =>
230	  CAP_MULTIPLIER * insuranceSumFor(insuredItems) - totalPaid;
231	
232	const claimResult = (
233	  steps: Step[],
234	  step: ClaimStep,
235	  alreadyPaid: number,
236	): { payout: number; remainingCap: number } => {
237	  const insuredItems = insuredItemsForPolicy(steps, step.policy);
238	  assertDamagesCoveredByPolicy(insuredItems, step.incident.damages);
239	  assertNonNegativeDamageAmounts(step.incident.damages);
240	  const capBeforePayout = remainingCapFor(insuredItems, alreadyPaid);
241	  const payout = roundDownToWholeGold(
242	    Math.min(claimPayout(insuredItems, step.incident.damages), capBeforePayout),
243	  );
244	  return { payout, remainingCap: capBeforePayout - payout };
245	};
246	
247	export const runScenario = (scenario: Scenario): ScenarioResult => {
248	  const paidByPolicy: Record<number, number> = {};
249	  return {
250	    results: scenario.steps.map((step, index) => {
251	      if (step.op === "quote") {
252	        return {
253	          premium: quotePremium(scenario.customer, step.items, index > 0),
254	        };
255	      }
256	      const alreadyPaid = paidByPolicy[step.policy] ?? 0;
257	      const result = claimResult(scenario.steps, step, alreadyPaid);
258	      paidByPolicy[step.policy] = alreadyPaid + result.payout;
259	      return result;
260	    }),
261	  };
262	};
